- Performance monitoring and alerting

### 5. Code Quality

- Test-driven development approach
- Clean architecture principles
- SOLID design principles
- Code review and quality gates
- Documentation and knowledge sharing

## Implementation Standards

### API Design Example

```typescript
// Express.js API with proper error handling and validation
import express, { Request, Response, NextFunction } from 'express';
import { body, validationResult } from 'express-validator';
import rateLimit from 'express-rate-limit';
import helmet from 'helmet';
import { authenticateJWT } from '../middleware/auth';
import { EmailService } from '../services/EmailService';
import { Logger } from '../utils/logger';

const router = express.Router();
const emailService = new EmailService();
const logger = new Logger('EmailController');

// Rate limiting
const emailProcessingLimit = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many email processing requests',
});

// Process email classification
router.post(
  '/emails/classify',
  helmet(),
  emailProcessingLimit,
  authenticateJWT,
  [
    body('emailId').isUUID().withMessage('Invalid email ID'),
    body('content').isLength({ min: 1 }).withMessage('Email content required'),
    body('priority').optional().isIn(['low', 'medium', 'high']),
  ],
  async (req: Request, res: Response, next: NextFunction) => {
    try {
      // Validate request
      const errors = validationResult(req);
      if (!errors.isEmpty()) {
        return res.status(400).json({
          error: 'Validation failed',
          details: errors.array(),
        });
      }

      const { emailId, content, priority = 'medium' } = req.body;
      const userId = req.user!.id;

      logger.info('Processing email classification', {
        emailId,
        userId,
        priority,
        correlationId: req.headers['x-correlation-id'],
      });

      // Process email asynchronously
      const result = await emailService.classifyEmail({
        emailId,
        content,
        priority,
        userId,
      });

      res.status(202).json({
        message: 'Email classification started',
        jobId: result.jobId,
        estimatedCompletion: result.estimatedCompletion,
      });
    } catch (error) {
      logger.error('Email classification failed', {
        error: error.message,
        emailId: req.body.emailId,
        userId: req.user?.id,
      });
      next(error);
    }
  }
);

export { router as emailRouter };
```

### Database Design Pattern

```sql
-- Optimized database schema with proper indexing
CREATE TABLE email_messages (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES users(id),
  gmail_message_id VARCHAR(255) UNIQUE NOT NULL,
  subject TEXT,
  content TEXT,
  sender_email VARCHAR(255) NOT NULL,
  received_at TIMESTAMP WITH TIME ZONE NOT NULL,
  processed_at TIMESTAMP WITH TIME ZONE,
  classification_result JSONB,
  processing_time_ms INTEGER,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Performance indexes
CREATE INDEX idx_email_messages_user_received ON email_messages(user_id, received_at DESC);
CREATE INDEX idx_email_messages_processing ON email_messages(processed_at) WHERE processed_at IS NULL;
CREATE INDEX idx_email_classification_result ON email_messages USING GIN(classification_result);

-- Partitioning for large datasets
CREATE TABLE email_messages_y2024m01 PARTITION OF email_messages
FOR VALUES FROM ('2024-01-01') TO ('2024-02-01');
```

### Service Layer Architecture

```typescript
// Service layer with dependency injection and error handling
export interface IEmailService {
  classifyEmail(request: ClassifyEmailRequest): Promise<ClassificationResult>;
  getEmailStatus(jobId: string): Promise<EmailStatus>;
}

export class EmailService implements IEmailService {
  constructor(
    private readonly emailRepository: IEmailRepository,
    private readonly classificationEngine: IClassificationEngine,
    private readonly queueService: IQueueService,
    private readonly logger: ILogger
  ) {}

  async classifyEmail(request: ClassifyEmailRequest): Promise<ClassificationResult> {
    const correlationId = generateCorrelationId();

    try {
      // Validate email doesn't already exist
      const existingEmail = await this.emailRepository.findByGmailId(request.emailId);

      if (existingEmail) {
        throw new EmailAlreadyProcessedError(request.emailId);
      }

      // Create email record
      const email = await this.emailRepository.create({
        gmailMessageId: request.emailId,
        content: request.content,
        userId: request.userId,
        priority: request.priority,
      });

      // Queue for asynchronous processing
      const job = await this.queueService.enqueue('email-classification', {
        emailId: email.id,
        priority: request.priority,
        correlationId,
      });

      this.logger.info('Email queued for classification', {
        emailId: email.id,
        jobId: job.id,
        correlationId,
      });

      return {
        jobId: job.id,
        estimatedCompletion: new Date(Date.now() + this.getEstimatedProcessingTime(request.priority)),
      };
    } catch (error) {
      this.logger.error('Failed to classify email', {
        error: error.message,
        request,
        correlationId,
      });
      throw error;
    }
  }

  private getEstimatedProcessingTime(priority: string): number {
    const times = { low: 60000, medium: 30000, high: 10000 };
    return times[priority] || times.medium;
  }
}
```

## Testing Strategy

