  });

  describe('classifyEmail', () => {
    it('should successfully queue email for classification', async () => {
      // Arrange
      const request = {
        emailId: 'test-email-id',
        content: 'Test email content',
        userId: 'user-123',
        priority: 'medium' as const,
      };

      mockEmailRepository.findByGmailId.mockResolvedValue(null);
      mockEmailRepository.create.mockResolvedValue(mockEmail);
      mockQueueService.enqueue.mockResolvedValue({ id: 'job-123' });

      // Act
      const result = await emailService.classifyEmail(request);

      // Assert
      expect(result.jobId).toBe('job-123');
      expect(mockQueueService.enqueue).toHaveBeenCalledWith(
        'email-classification',
        expect.objectContaining({
          emailId: mockEmail.id,
          priority: 'medium',
        })
      );
    });

    it('should throw error for duplicate email', async () => {
      // Arrange
      const request = createClassifyEmailRequest();
      mockEmailRepository.findByGmailId.mockResolvedValue(mockEmail);

      // Act & Assert
      await expect(emailService.classifyEmail(request)).rejects.toThrow(EmailAlreadyProcessedError);
    });
  });
});
