```typescript
// JWT middleware with proper validation
export const authenticateJWT = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const authHeader = req.headers.authorization;

    if (!authHeader?.startsWith('Bearer ')) {
      return res.status(401).json({ error: 'Missing or invalid authorization header' });
    }

    const token = authHeader.substring(7);
    const decoded = jwt.verify(token, process.env.JWT_SECRET!) as JWTPayload;

    // Validate token hasn't been revoked
    const isRevoked = await tokenBlacklist.isRevoked(decoded.jti);
    if (isRevoked) {
      return res.status(401).json({ error: 'Token has been revoked' });
    }

    // Attach user info to request
    req.user = {
      id: decoded.sub,
      email: decoded.email,
      roles: decoded.roles,
    };

    next();
  } catch (error) {
    logger.warn('JWT authentication failed', {
      error: error.message,
      ip: req.ip,
      userAgent: req.get('User-Agent'),
    });

    return res.status(401).json({ error: 'Invalid token' });
  }
};
```

## Performance Optimization

### Caching Strategy

```typescript
// Multi-level caching implementation
export class CacheService {
  constructor(
    private readonly redisClient: Redis,
    private readonly memoryCache: NodeCache
  ) {}

  async get<T>(key: string): Promise<T | null> {
    // L1: Memory cache (fastest)
    const memoryResult = this.memoryCache.get<T>(key);
    if (memoryResult !== undefined) {
      return memoryResult;
    }

    // L2: Redis cache (network call)
    const redisResult = await this.redisClient.get(key);
    if (redisResult) {
      const parsed = JSON.parse(redisResult) as T;
      // Backfill memory cache
      this.memoryCache.set(key, parsed, 300); // 5 minutes
      return parsed;
    }

    return null;
  }

  async set<T>(key: string, value: T, ttlSeconds: number): Promise<void> {
    // Set in both caches
    this.memoryCache.set(key, value, ttlSeconds);
    await this.redisClient.setex(key, ttlSeconds, JSON.stringify(value));
  }
}
```

