### API Security Implementation

```typescript
// Comprehensive API security middleware
import rateLimit from 'express-rate-limit';
import slowDown from 'express-slow-down';
import helmet from 'helmet';
import cors from 'cors';
import { body, query, param, validationResult } from 'express-validator';
import { authenticate, authorize } from '../auth/middleware';
import { APIKeyAuth } from '../auth/apikey';
import { Logger } from '../utils/logger';

const logger = new Logger('APISecurityMiddleware');

// Rate limiting with different tiers
const createRateLimit = (windowMs: number, max: number, tier: string) => {
  return rateLimit({
    windowMs,
    max,
    message: {
      error: 'Rate limit exceeded',
      tier,
      retryAfter: Math.ceil(windowMs / 1000),
    },
    standardHeaders: true,
    legacyHeaders: false,
    keyGenerator: (req) => {
      // Use API key or IP for rate limiting
      return req.apiKey?.id || req.ip;
    },
    onLimitReached: (req, res) => {
      logger.warn('Rate limit exceeded', {
        ip: req.ip,
        apiKey: req.apiKey?.id,
        endpoint: req.path,
        tier,
      });
    },
  });
};

// Different rate limits for different API tiers
export const rateLimits = {
  free: createRateLimit(60 * 1000, 100, 'free'), // 100 req/min
  pro: createRateLimit(60 * 1000, 1000, 'pro'), // 1000 req/min
  enterprise: createRateLimit(60 * 1000, 10000, 'enterprise'), // 10k req/min
};

// Progressive delay for suspicious behavior
export const speedLimiter = slowDown({
  windowMs: 15 * 60 * 1000, // 15 minutes
  delayAfter: 50, // allow 50 requests per windowMs without delay
  delayMs: 100, // add 100ms delay per request after delayAfter
  maxDelayMs: 20000, // max delay of 20 seconds
});

// CORS configuration
export const corsOptions = {
  origin: (origin: string | undefined, callback: Function) => {
    // Allow requests with no origin (mobile apps, etc.)
    if (!origin) return callback(null, true);

    // Check against allowlist
    const allowedOrigins = process.env.ALLOWED_ORIGINS?.split(',') || [];

    if (allowedOrigins.includes(origin)) {
      callback(null, true);
    } else {
      logger.warn('CORS origin rejected', { origin });
      callback(new Error('Not allowed by CORS'));
    }
  },
  credentials: true,
  optionsSuccessStatus: 200,
};

// Input validation schemas
export const emailClassificationValidation = [
  body('content')
    .isLength({ min: 1, max: 100000 })
    .withMessage('Content must be between 1 and 100,000 characters')
    .customSanitizer((value) => {
      // Remove potentially dangerous content
      return value
        .replace(/<script[^>]*>.*?<\/script>/gi, '')
        .replace(/<[^>]*>/g, '')
        .trim();
    }),

  body('sender').optional().isEmail().normalizeEmail().withMessage('Sender must be a valid email address'),

  body('async').optional().isBoolean().withMessage('Async must be a boolean'),

  body('webhook_url')
    .if(body('async').equals(true))
    .isURL({ protocols: ['https'] })
    .withMessage('Webhook URL must be a valid HTTPS URL'),

  body('options.confidence_threshold')
    .optional()
    .isFloat({ min: 0, max: 1 })
    .withMessage('Confidence threshold must be between 0 and 1'),
];

// Security middleware chain
export const securityMiddleware = [
  helmet({
    contentSecurityPolicy: {
      directives: {
        defaultSrc: ["'self'"],
        styleSrc: ["'self'", "'unsafe-inline'"],
        scriptSrc: ["'self'"],
        imgSrc: ["'self'", 'data:', 'https:'],
      },
    },
    hsts: {
      maxAge: 31536000,
      includeSubDomains: true,
      preload: true,
    },
  }),
  cors(corsOptions),
  speedLimiter,
];

// Authentication middleware
export const authMiddleware = [
  APIKeyAuth.authenticate,
  authenticate, // JWT authentication
  (req: Request, res: Response, next: NextFunction) => {
    // Apply appropriate rate limit based on API tier
    const tier = req.apiKey?.tier || 'free';
    const rateLimit = rateLimits[tier as keyof typeof rateLimits];
    rateLimit(req, res, next);
  },
];

// Validation error handler
export const handleValidationErrors = (req: Request, res: Response, next: NextFunction) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    logger.warn('Validation failed', {
      errors: errors.array(),
      endpoint: req.path,
      apiKey: req.apiKey?.id,
    });

    return res.status(400).json({
      error: 'Validation failed',
      details: errors.array().map((err) => ({
        field: err.param,
        message: err.msg,
        value: err.value,
      })),
    });
  }
  next();
};
