### API Performance Optimization

```typescript
// Performance monitoring and optimization
import compression from 'compression';
import { createProxyMiddleware } from 'http-proxy-middleware';
import NodeCache from 'node-cache';
import { promisify } from 'util';
import redis from 'redis';

// Response caching middleware
class APICache {
  private cache: NodeCache;
  private redisClient: redis.RedisClient;

  constructor() {
    this.cache = new NodeCache({ stdTTL: 300 }); // 5 minutes default
    this.redisClient = redis.createClient(process.env.REDIS_URL);
  }

  middleware() {
    return async (req: Request, res: Response, next: NextFunction) => {
      // Only cache GET requests
      if (req.method !== 'GET') return next();

      const cacheKey = this.generateCacheKey(req);

      try {
        // Check memory cache first
        const cached = this.cache.get(cacheKey);
        if (cached) {
          res.set('X-Cache', 'HIT-MEMORY');
          return res.json(cached);
        }

        // Check Redis cache
        const redisCached = await this.redisClient.get(cacheKey);
        if (redisCached) {
          const data = JSON.parse(redisCached);
          this.cache.set(cacheKey, data, 60); // Cache in memory for 1 minute
          res.set('X-Cache', 'HIT-REDIS');
          return res.json(data);
        }

        // No cache hit, continue to route handler
        res.set('X-Cache', 'MISS');

        // Intercept response to cache it
        const originalJson = res.json;
        res.json = function (data: any) {
          // Cache successful responses
          if (res.statusCode === 200) {
            const ttl = req.headers['cache-control'] ? this.parseCacheControl(req.headers['cache-control']) : 300;

            this.cache.set(cacheKey, data, ttl);
            this.redisClient.setex(cacheKey, ttl, JSON.stringify(data));
          }

          return originalJson.call(this, data);
        }.bind(this);

        next();
      } catch (error) {
        logger.error('Cache middleware error', { error, cacheKey });
        next();
      }
    };
  }

  private generateCacheKey(req: Request): string {
    const { path, query, user } = req;
    return `api:${path}:${JSON.stringify(query)}:${user?.id || 'anonymous'}`;
  }
}

// Request/Response optimization
export const performanceMiddleware = [
  // Gzip compression
  compression({
    filter: (req, res) => {
      if (req.headers['x-no-compression']) return false;
      return compression.filter(req, res);
    },
    threshold: 1024, // Only compress responses > 1KB
  }),

  // Response optimization
  (req: Request, res: Response, next: NextFunction) => {
    // Set performance headers
    res.set({
      'X-Content-Type-Options': 'nosniff',
      'X-Frame-Options': 'DENY',
      'X-XSS-Protection': '1; mode=block',
      'Cache-Control': 'public, max-age=300', // 5 minutes default cache
      ETag: `"${Date.now()}"`, // Simple ETag for caching
    });

    // Add response time tracking
    const start = process.hrtime();

    res.on('finish', () => {
      const [seconds, nanoseconds] = process.hrtime(start);
      const duration = seconds * 1000 + nanoseconds / 1000000; // Convert to milliseconds

      res.set('X-Response-Time', `${duration.toFixed(2)}ms`);

      // Log slow requests
      if (duration > 1000) {
        logger.warn('Slow API request', {
          method: req.method,
          path: req.path,
          duration: duration,
          userAgent: req.get('User-Agent'),
          ip: req.ip,
        });
      }
    });

    next();
  },
];
