// API contract testing with Jest and Supertest
import request from 'supertest';
import { app } from '../app';
import { generateTestJWT, createTestUser } from '../utils/test-helpers';

describe('Email Classification API', () => {
  let testUser: any;
  let authToken: string;

  beforeAll(async () => {
    testUser = await createTestUser({
      email: 'test@example.com',
      tier: 'pro',
    });
    authToken = generateTestJWT(testUser);
  });

  describe('POST /emails/classify', () => {
    it('should classify email successfully with valid input', async () => {
      const response = await request(app)
        .post('/v2/emails/classify')
        .set('Authorization', `Bearer ${authToken}`)
        .send({
          content: 'Meeting tomorrow at 3 PM in conference room A',
          sender: 'manager@company.com',
        })
        .expect(200);

      expect(response.body).toMatchObject({
        email_id: expect.any(String),
        categories: expect.arrayContaining([
          expect.objectContaining({
            name: expect.any(String),
            confidence: expect.any(Number),
            reasoning: expect.any(String),
          }),
        ]),
        processing_time_ms: expect.any(Number),
      });

      // Validate confidence scores are between 0 and 1
      response.body.categories.forEach((category: any) => {
        expect(category.confidence).toBeGreaterThanOrEqual(0);
        expect(category.confidence).toBeLessThanOrEqual(1);
      });
    });

    it('should return validation error for invalid input', async () => {
      const response = await request(app)
        .post('/v2/emails/classify')
        .set('Authorization', `Bearer ${authToken}`)
        .send({
          content: '', // Invalid: empty content
          sender: 'invalid-email', // Invalid: not an email
        })
        .expect(400);

      expect(response.body).toMatchObject({
        error: 'Validation failed',
        details: expect.arrayContaining([
          expect.objectContaining({
            field: 'content',
            message: expect.stringContaining('required'),
          }),
          expect.objectContaining({
            field: 'sender',
            message: expect.stringContaining('valid email'),
          }),
        ]),
      });
    });

    it('should respect rate limits', async () => {
      // Make requests up to the rate limit
      const requests = Array(100)
        .fill(null)
        .map(() =>
          request(app).post('/v2/emails/classify').set('Authorization', `Bearer ${authToken}`).send({
            content: 'Test email content',
            sender: 'test@example.com',
          })
        );

      await Promise.all(requests);

      // Next request should be rate limited
      await request(app)
        .post('/v2/emails/classify')
        .set('Authorization', `Bearer ${authToken}`)
        .send({
          content: 'Test email content',
          sender: 'test@example.com',
        })
        .expect(429);
    });

    it('should handle async processing correctly', async () => {
      const response = await request(app)
        .post('/v2/emails/classify')
        .set('Authorization', `Bearer ${authToken}`)
        .send({
          content: 'Large email content for async processing',
          async: true,
          webhook_url: 'https://example.com/webhook',
        })
        .expect(202);

      expect(response.body).toMatchObject({
        job_id: expect.any(String),
        estimated_completion: expect.any(String),
        status: 'processing',
      });
    });
  });

  describe('API Documentation', () => {
    it('should serve OpenAPI specification', async () => {
      const response = await request(app).get('/api-docs/spec.json').expect(200).expect('Content-Type', /json/);

      expect(response.body).toHaveProperty('openapi');
      expect(response.body).toHaveProperty('info.title');
      expect(response.body).toHaveProperty('paths');
    });

    it('should serve interactive documentation', async () => {
      await request(app).get('/api-docs').expect(200).expect('Content-Type', /html/);
    });
  });

  describe('Security', () => {
    it('should reject requests without authentication', async () => {
      await request(app)
        .post('/v2/emails/classify')
        .send({
          content: 'Test email content',
        })
        .expect(401);
    });

    it('should reject requests with invalid JWT', async () => {
      await request(app)
        .post('/v2/emails/classify')
        .set('Authorization', 'Bearer invalid.jwt.token')
        .send({
          content: 'Test email content',
        })
        .expect(401);
    });

    it('should sanitize malicious input', async () => {
      const response = await request(app)
        .post('/v2/emails/classify')
        .set('Authorization', `Bearer ${authToken}`)
        .send({
          content: '<script>alert("xss")</script>Meeting tomorrow',
          sender: 'test@example.com',
        })
        .expect(200);

      // Script tags should be removed
      expect(response.body.processed_content).not.toContain('<script>');
    });
  });
});

